  "BC_ENGAGEMENT_INPUT": {
    "idea_id": "",
    "thesis": "",
    "comment_prompt_seed": "",
    "key_stats": [
      {
        "stat": "",
        "figure": "",
        "source_id": ""
      }
    ],
    "closing_emotion": "",
    "cta_subscribe": ""
  }
}
